parameters.text:
=Search for UGC content creators with the following requirements:

Platform: {{ $('Webhook').first().json.body.platform }}
Country: {{ $('Webhook').first().json.body.country }}
Language: {{ $('Webhook').first().json.body.language }}
Gender: {{ $('Webhook').first().json.body.gender }}
Keyword/Niche: {{ $('Webhook').first().json.body.keyword }}
Minimum Followers: {{ $('Webhook').first().json.body.min_followers }}
Maximum Followers: {{ $('Webhook').first().json.body.max_followers }}
Minimum Videos: {{ $('Webhook').first().json.body.min_videos }}

Find matching profiles now.

parameters.jsCode:
let rawText = $json.output;
let dataArray = null;
let parseError = null;

try {
  let cleanText = rawText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();

  const jsonMatch = cleanText.match(/\[\s*\{[\s\S]*\}\s*\]/m);
  if (jsonMatch) {
    cleanText = jsonMatch[0];
  }

  dataArray = JSON.parse(cleanText);
} catch (e) {
  parseError = e.message;
}

if (!dataArray || !Array.isArray(dataArray)) {
  return [{
    json: {
      success: false,
      error: 'AI returned invalid response',
      parse_error: parseError || 'Not a JSON array',
      creators: [],
      total_found: 0
    }
  }];
}

if (dataArray.length === 0) {
  return [{
    json: {
      success: true,
      message: 'No creators found matching your criteria.',
      creators: [],
      total_found: 0
    }
  }];
}

const creators = dataArray.map(c => ({
  name: c.name || 'Unknown',
  profile_url: c.profile_url || '',
  follower_count: typeof c.follower_count === 'number'
    ? c.follower_count
    : parseInt(String(c.follower_count).replace(/[^0-9]/g, '')) || 0,
  videos_count: typeof c.videos_count === 'number'
    ? c.videos_count
    : parseInt(String(c.videos_count || c.videos_cout || '0').replace(/[^0-9]/g, '')) || 0,
  contact_info: c.contact_info || 'N/A',
  country: c.country || '',
  language: c.language || '',
  gender: c.gender || '',
  niche: c.niche || ''
}));

const valid = creators.filter(c => c.profile_url && c.profile_url.startsWith('http'));

return [{
  json: {
    success: true,
    total_found: valid.length,
    creators: valid
  }
}];

