parameters.jsCode:
const rawMessage = $json.output || '';

return [{
  json: {
    success: true,
    message: rawMessage.trim(),
    generated_at: new Date().toISOString()
  }
}];

const body = $('Webhook').first().json.body;

let subject = 'Collaboration Opportunity - ' + (body.campaign_name || 'Campaign');
let emailBody = body.message_body || '';

if (emailBody.startsWith('Subject:')) {
  const firstNewline = emailBody.indexOf('\n');
  if (firstNewline > 0) {
    subject = emailBody.substring(8, firstNewline).trim();
    emailBody = emailBody.substring(firstNewline + 1).trim();
  }
}

return [{
  json: {
    success: true,
    to: body.creator_email,
    subject: subject,
    body: emailBody,
    message_id: body.message_id,
    sent_at: new Date().toISOString()
  }
}];
